// Guardar resultado del período y lanzar query de saldo inicial
msg._periodRows = msg.payload;  // guardar resultado de Query A
msg.payload = msg._querySaldoInicial;  // inyectar Query B
node.warn('[Sync-SS-v3] Periodo: ' + (Array.isArray(msg._periodRows) ? msg._periodRows.length : 0) + ' filas. Ejecutando saldo inicial...');
return msg;

// ===============================================
// Merge: combinar período + saldo inicial → 2D array (11 columnas A-K)
// ===============================================
var periodRows = msg._periodRows || [];
var siRows = msg.payload || [];  // resultado de Query B (saldo inicial)
var sync_uuid = msg.sync_uuid || 'N/A';
var startDate = msg.startDate || '';
var endDate = msg.endDate || '';
var timestamp = new Date().toISOString();
var periodo = startDate + '-' + endDate;

// Indexar saldo inicial por CODIGO
var siMap = {};
for (var i = 0; i < siRows.length; i++) {
  siMap[siRows[i].CODIGO || ''] = parseFloat(siRows[i].SALDO_INICIAL) || 0;
}

// Guardar metadata
msg._syncInfo = {
  sync_uuid: sync_uuid,
  periodo: periodo,
  timestamp: timestamp
};

if (!periodRows || !Array.isArray(periodRows) || periodRows.length === 0) {
  node.warn('[Sync-SS-v3] Sin datos de periodo. Se omite escritura.');
  msg._syncInfo.empty = true;
  msg.payload = null;
  return msg;
}

// Construir array 2D con 11 columnas (A-K)
var data = [];
for (var i = 0; i < periodRows.length; i++) {
  var r = periodRows[i];
  var codigo = r.CODIGO || '';
  var debe = parseFloat(r.DEBE_PERIODO) || 0;
  var haber = parseFloat(r.HABER_PERIODO) || 0;
  var saldo = debe - haber;
  var saldoInicial = siMap[codigo] || 0;

  data.push([
    codigo,                            // A: CODIGO
    r.CUENTA || '',                    // B: CUENTA
    r.NRubro || '',                    // C: RUBRO
    debe,                              // D: DEBE_PERIODO
    haber,                             // E: HABER_PERIODO
    saldo,                             // F: SALDO_PERIODO
    periodo,                           // G: PERIODO
    timestamp,                         // H: FECHA_SYNC
    sync_uuid,                         // I: SYNC_UUID
    '',                                // J: UNIDAD_NEGOCIO (placeholder, se completa en otro flujo)
    saldoInicial                       // K: SALDO_INICIAL  ← NUEVA
  ]);
}

msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-SS-v3] ' + data.length + ' filas con saldo inicial. UUID=' + sync_uuid);
return msg;

// ===============================================
// Transformar → 2D array con columnas extra (ya viene mergeado)
// ===============================================
// El merge anterior ya produce el array 2D con 11 columnas A-K
// Este nodo solo valida y pasa los datos para mantener compatibilidad

var data = msg.payload;

if (!data || !Array.isArray(data) || data.length === 0) {
  node.warn('[Sync-SS-v3] Sin datos para sync. Se omite escritura.');
  msg._syncInfo = msg._syncInfo || {};
  msg._syncInfo.empty = true;
  msg.payload = null;
  return msg;
}

// Validar que cada fila tenga 11 columnas
for (var i = 0; i < data.length; i++) {
  while (data[i].length < 11) data[i].push('');
}

msg._syncInfo.rowCount = data.length;
node.warn('[Sync-SS-v3] ' + data.length + ' filas listas para Google Sheets (A-K). UUID=' + (msg._syncInfo.sync_uuid || '?'));
return msg;

// ===============================================
// Procesar resultado del sync a Google Sheets
// ===============================================
var info = msg._syncInfo || {};

if (info.empty) {
  node.warn('[Sync-SS-v3] Sync omitido: sin datos en el periodo ' + (info.periodo || '?'));
  return msg;
}

// El GSheet node devuelve en msg.payload la respuesta de la API
// Si hay error, msg.error tendrá el mensaje
if (msg.error) {
  node.error('[Sync-SS-v3] ERROR al escribir en Google Sheets: ' + msg.error);
  return msg;
}

var updatedRange = '';
if (msg.payload && msg.payload.updates) {
  updatedRange = msg.payload.updates.updatedRange || '';
}

node.warn('[Sync-SS-v3] ✅ Sync exitoso a Google Sheets');
node.warn('[Sync-SS-v3]    UUID: ' + (info.sync_uuid || '?'));
node.warn('[Sync-SS-v3]    Periodo: ' + (info.periodo || '?'));
node.warn('[Sync-SS-v3]    Filas: ' + (info.rowCount || 0));
node.warn('[Sync-SS-v3]    Rango: ' + updatedRange);

// Pasar metadata para nodos siguientes si se agregaran
msg._syncResult = {
  success: true,
  uuid: info.sync_uuid,
  periodo: info.periodo,
  rows: info.rowCount,
  range: updatedRange,
  timestamp: info.timestamp
};

return msg;

// ===============================================
// Preparar queries: Sumas y Saldos del período + Saldo Inicial
// ===============================================
var now = new Date();
var y = now.getFullYear();
var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
var startDate = y + m + '01';
var endDate = y + m + String(lastDay).padStart(2, '0');

// Generar UUID de sync
var sync_uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase()
);

msg.startDate = startDate;
msg.endDate = endDate;
msg.sync_uuid = sync_uuid;

// Query A: Sumas y Saldos del período
var queryPeriodo = ""
 + "SELECT TOP 1000 \n"
 + "   V_EZI_CUENTAS.CODIGO,\n"
 + "   V_EZI_CUENTAS.DESCRIPCION AS CUENTA,\n"
 + "   V_EZI_CUENTAS.CRubro,\n"
 + "   V_EZI_CUENTAS.NRubro,\n"
 + "   ISNULL(SUM(V_VALOR_.IMPORTE), 0) AS DEBE_PERIODO,\n"
 + "   ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS HABER_PERIODO,\n"
 + "   ISNULL(SUM(V_VALOR_.IMPORTE), 0) - ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS SALDO_PERIODO\n"
 + "FROM V_TRCONTABLE_\n"
 + "INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID\n"
 + "INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID\n"
 + "INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID\n"
 + "INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID\n"
 + "WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) >= '" + startDate + "'\n"
 + "  AND SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) <= '" + endDate + "'\n"
 + "  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'\n"
 + "  AND V_TRCONTABLE_.ESTADO = 'C'\n"
 + "GROUP BY\n"
 + "     V_EZI_CUENTAS.CODIGO,\n"
 + "     V_EZI_CUENTAS.DESCRIPCION,\n"
 + "     V_EZI_CUENTAS.CRubro,\n"
 + "     V_EZI_CUENTAS.NRubro\n"
 + "ORDER BY V_EZI_CUENTAS.CODIGO;\n";

// Query B: Saldo Inicial acumulado anterior al período
var querySaldoInicial = ""
 + "SELECT \n"
 + "   V_EZI_CUENTAS.CODIGO,\n"
 + "   ISNULL(SUM(V_VALOR_.IMPORTE), 0) - ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS SALDO_INICIAL\n"
 + "FROM V_TRCONTABLE_\n"
 + "INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID\n"
 + "INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID\n"
 + "INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID\n"
 + "INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID\n"
 + "WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) < '" + startDate + "'\n"
 + "  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'\n"
 + "  AND V_TRCONTABLE_.ESTADO = 'C'\n"
 + "GROUP BY V_EZI_CUENTAS.CODIGO\n"
 + "ORDER BY V_EZI_CUENTAS.CODIGO;\n";

// Pasar Query A en msg.payload (el nodo MSSQL la lee desde ahí)
msg.payload = queryPeriodo;
// Guardar Query B para después
msg._querySaldoInicial = querySaldoInicial;

node.warn('[Sync-SS-v3] Preparando sync ' + sync_uuid + ' periodo ' + startDate + '-' + endDate);
return msg;
